// // This module implements an 8-bit wide 2-to-1 multiplexer with enable. When the enable signal is high, it selects the second input if the select signal is high; otherwise, it selects the first input. If the enable signal is low, the output is zero.
module mux_2to1_en (
  input [7:0] a,
  input [7:0] b,
  input sel,
  input en,
  output [7:0] y
);

  assign y = en ? (sel ? b : a) : 8'b00000000;

endmodule
